import{_ as l,o,c as i,a2 as a}from"./chunks/framework.CE5oItKu.js";const m=JSON.parse('{"title":"后端代码规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/backend/01-code.md","filePath":"mango-pmo/rules/backend/01-code.md"}'),c={name:"mango-pmo/rules/backend/01-code.md"};function d(r,e,t,n,h,u){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="后端代码规范" tabindex="-1">后端代码规范 <a class="header-anchor" href="#后端代码规范" aria-label="Permalink to &quot;后端代码规范&quot;">​</a></h1><h2 id="_1-基本规则" tabindex="-1">1. 基本规则 <a class="header-anchor" href="#_1-基本规则" aria-label="Permalink to &quot;1. 基本规则&quot;">​</a></h2><ul><li>代码必须可读、可测、可维护。</li><li>同一逻辑只保留一份实现。</li><li>不写无意义包装层。</li><li>不把临时方案当正式方案提交。</li></ul><h2 id="_2-复杂度控制" tabindex="-1">2. 复杂度控制 <a class="header-anchor" href="#_2-复杂度控制" aria-label="Permalink to &quot;2. 复杂度控制&quot;">​</a></h2><ul><li>方法保持简短。</li><li>类职责保持单一。</li><li>一个类只解决一类问题。</li><li>超过当前抽象层职责的逻辑必须下沉或拆分。</li></ul><h2 id="_3-异常处理" tabindex="-1">3. 异常处理 <a class="header-anchor" href="#_3-异常处理" aria-label="Permalink to &quot;3. 异常处理&quot;">​</a></h2><ul><li>只捕获明确异常。</li><li>捕获后必须处理或继续抛出。</li><li>禁止吞异常。</li><li>禁止直接捕获 <code>Exception</code> 或 <code>Throwable</code> 作为常规写法。</li></ul><h2 id="_4-前置条件校验" tabindex="-1">4. 前置条件校验 <a class="header-anchor" href="#_4-前置条件校验" aria-label="Permalink to &quot;4. 前置条件校验&quot;">​</a></h2><ul><li>业务逻辑入口必须先做前置条件校验。</li><li>业务前置条件统一使用 <code>Require</code>。</li><li>禁止在业务逻辑中直接写 <code>if (...) throw ...</code> 做前置条件校验。</li><li>禁止用 <code>if (...) return ...</code> 跳过非法参数处理。</li><li><code>Require</code> 失败统一抛业务异常。</li></ul><h2 id="_5-安全要求" tabindex="-1">5. 安全要求 <a class="header-anchor" href="#_5-安全要求" aria-label="Permalink to &quot;5. 安全要求&quot;">​</a></h2><ul><li>禁止硬编码密钥、口令、地址、账号。</li><li>禁止 SQL 拼接。</li><li>输入必须校验。</li><li>日志禁止输出敏感信息。</li></ul><h2 id="_5-1-文件引用规则" tabindex="-1">5.1 文件引用规则 <a class="header-anchor" href="#_5-1-文件引用规则" aria-label="Permalink to &quot;5.1 文件引用规则&quot;">​</a></h2><ul><li>业务模块禁止持久化文件访问地址，包括 <code>url</code>、<code>previewUrl</code>、<code>downloadUrl</code>、对象存储直连地址、预签名 URL、临时预览地址。</li><li>业务表只能保存文件中心标识或引用关系，例如 <code>file_id</code>、<code>file_ids</code>、<code>mango-file:{id}</code> token、业务附件关联表。</li><li>业务模块需要预览、下载、归档、权限校验、派生文件处理时，必须通过 <code>mango-file</code> 按文件 ID 操作。</li><li>文件访问地址属于运行时派生数据，不能写入业务实体、业务扩展字段、JSON 配置或缓存作为长期数据。</li></ul><h2 id="_6-质量要求" tabindex="-1">6. 质量要求 <a class="header-anchor" href="#_6-质量要求" aria-label="Permalink to &quot;6. 质量要求&quot;">​</a></h2><ul><li>提交前统一执行 <code>mvn mango:check -Drule=all</code>。</li><li>涉及测试设计、测试归属、有效测试判断，遵循 <code>mango-pmo/rules/backend/08-test.md</code>。</li><li><code>mango:check</code> 对内聚合 <code>mango-check</code>、<code>pmd</code>、<code>checkstyle</code>、<code>spotbugs</code>，是项目质量验收的唯一入口。</li><li>通用代码质量规则由 P3C/PMD/Checkstyle 负责，例如方法长度、类长度、复杂度、异常吞掉、空 catch、硬编码等。</li><li><code>mango:check</code> 是项目统一检查入口，但插件实现只负责 Mango 项目特有规则，例如模块命名、模块边界、<code>api/core/starter</code> 职责、KV key、测试物料一致性、<code>module.properties</code>、远程适配。</li><li><code>mango:check</code> 报告必须标识规则来源，例如 <code>mango-check</code>、<code>pmd</code>、<code>checkstyle</code>、<code>spotbugs</code>。</li><li>命名规则按工具分工执行：Java 类、方法、字段命名交给 P3C/Checkstyle；P3C/Checkstyle 覆盖不到的 Mango 模块命名保留在 <code>mvn mango:check -Drule=naming</code>。</li><li>Javadoc 采用契约优先策略，不追求形式完整： <ul><li>API、SPI、注解、配置类必须写有语义的 Javadoc。</li><li>public 方法暴露契约时，说明参数约束、返回语义、异常或边界。</li><li>枚举值必须说明业务含义。</li><li>getter/setter、简单字段、显然方法不强制写 Javadoc。</li><li><code>@author</code>、Javadoc 首句句号等形式规则不作为 Mango 质量规则。</li></ul></li><li>明显重复代码必须抽取。</li><li>明显无用代码必须删除。</li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li>复制代码后长期保留重复实现</li><li>为了通过检查而绕过规则</li><li>把基础设施细节直接扩散到业务层</li><li>在业务逻辑里到处散写参数 <code>if/throw</code></li><li>在业务数据中保存文件下载、预览或对象存储访问地址</li></ul>',17)])])}const _=l(c,[["render",d]]);export{m as __pageData,_ as default};
